var e=JSON.parse(`[{"id":"L4_1","type":"dialog","speaker":"LEEJIN_ALPHA_NULL_NULL","text":{"KOREA":"…사정상, 한동안 연락드리지 못한 점 사과드립니다.","JPN":"……都合上、しばらく連絡できなかった点、申し訳ございません。","ENG":"I’m sorry for staying silent for so long...","TWN":"…很抱歉，因為一些原因，許久未能聯絡。"},"stage":{"bg":"AB_UI_NKM_UI_CUTSCEN_BG_MAINSTREAM_001010","slots":{"L":null,"C":null,"R":null}}},{"id":"L5_1","type":"dialog","speaker":"LEEJIN_ALPHA_NULL_NULL","text":{"KOREA":"벌써 시간이 꽤 지난 일이긴 합니다만…….","JPN":"もう随分前の出来事ではありますが……","ENG":"It's been quite some time but...","TWN":"雖然已經過有點久……"},"stage":{"bg":"AB_UI_NKM_UI_CUTSCEN_BG_MAINSTREAM_001010","slots":{"L":null,"C":null,"R":null}}},{"id":"L6_1","type":"dialog","speaker":"LEEJIN_ALPHA_NULL_NULL","text":{"KOREA":"정기 보고 형식상, 시간 경과대로 진술하도록 하겠습니다.","JPN":"定期報告の形式上、時間の経過順に述べさせていただきます。","ENG":"I’ll give you a timeline report in accordance with the official format.","TWN":"但我還是以定期報告的方式，按時間發生順序進行陳述。"},"stage":{"bg":"AB_UI_NKM_UI_CUTSCEN_BG_MAINSTREAM_001010","slots":{"L":null,"C":null,"R":null}}},{"id":"L8_1","type":"dialog","speaker":"LEEJIN_ALPHA_NULL_NULL","text":{"KOREA":"먼저, 가족 모임 당시 있었던 일입니다.","JPN":"まずは、家族会の時にあった出来事です。","ENG":"Let me start with what happened at the family meeting.","TWN":"首先是家族聚會時的事情。"},"stage":{"bg":"AB_UI_NKM_UI_CUTSCEN_BG_MAINSTREAM_001010","slots":{"L":null,"C":null,"R":null}}},{"id":"L9_1","type":"dialog","speaker":"LEEJIN_ALPHA_NULL_NULL","text":{"KOREA":"예식을 마친 뒤 세대별로 회동을 가졌다는 건 알고 계실 겁니다.","JPN":"礼式の後、世代別の集まりがあったことはご存知でしょう？","ENG":"You may know that each generation holds its own meetings.","TWN":"您也知道，儀式過後會各自帶開討論。"},"stage":{"bg":"AB_UI_NKM_UI_CUTSCEN_BG_MAINSTREAM_001010","slots":{"L":null,"C":null,"R":null}}},{"id":"L10_1","type":"dialog","speaker":"LEEJIN_ALPHA_NULL_NULL","text":{"KOREA":"자제 분들도 각자 그룹 계열사를 맡고 있으니만큼, 사실상 경영 얘기가 주된 화제였죠.","JPN":"ご子息もそれぞれグループの系列会社を管理しているため、事実上経営の話が主な話題でした。","ENG":"Since they are running their own companies, the main topic of the meeting was their businesses.","TWN":"畢竟小姐、少爺們都有各自負責集團的分公司，所以大部分的話題都圍繞在公司經營上。"},"stage":{"bg":"AB_UI_NKM_UI_CUTSCEN_BG_MAINSTREAM_001010","slots":{"L":null,"C":null,"R":null}}},{"id":"L13_1","type":"dialog","speaker":"HEAVYARMSCEO_NPC_ALPHA_NULL","text":{"KOREA":"…그러니까 누님! 우리도 어렵다니까!","JPN":"……だから、姉さん！　うちも厳しいんだって！","ENG":"Sis, I’m telling you. We have our own issues!","TWN":"…我說大姊！我們也很為難啊！"},"stage":{"bg":"CLUB1","slots":{"L":null,"C":null,"R":null}}},{"id":"L14_1","type":"dialog","speaker":"HEAVYARMSCEO_NPC_ALPHA_NULL","text":{"KOREA":"우리가 뭐 돈을 못 벌고 싶어서 못 벌어? 돈 벌 각이 안 나오잖아, 지금!","JPN":"こっちだってそりゃ、稼げるもんなら稼ぎたいよ！　でも今は八方塞がりなんだ！","ENG":"You think we’re not making money because we don’t want to? Look at the situation!","TWN":"你以為我們是嫌錢太多，不想賺錢嗎？就時機不好嘛！"},"stage":{"bg":"CLUB1","slots":{"L":null,"C":null,"R":null}}},{"id":"L15_1","type":"dialog","speaker":"HEAVYARMSCEO_NPC_ALPHA_NULL","text":{"KOREA":"이터니움 값은 치솟고 국제 정세는 맨날 불안한데 소비가 위축되는게 당연하지!","JPN":"エタニウムはどんどん高くなって、国家情勢はずっと不安定なこの状況で、消費が萎縮するのは当たり前だ！","ENG":"The cost of Eternium is going sky high, and the world is unstable. It’s obvious that consumption decreases!","TWN":"永恆之金的價格一直在漲，國際局勢又這麼不穩，消費萎縮是正常的嘛！"},"stage":{"bg":"CLUB1","slots":{"L":null,"C":null,"R":null}}},{"id":"L16_1","type":"dialog","speaker":"ENTERTAINMENTCEO_NPC_ALPHA_NULL","text":{"KOREA":"무기 팔아야 하는 애가 그런 소리를 하니?","JPN":"武器商売をする人間が、そんなことを言ってどうするの？","ENG":"What? You’re selling weapons!","TWN":"賣武器維生的傢伙怎麼說這種話？"},"stage":{"bg":"CLUB1","slots":{"L":null,"C":null,"R":null}}},{"id":"L17_1","type":"dialog","speaker":"ENTERTAINMENTCEO_NPC_ALPHA_NULL","text":{"KOREA":"그냥 속 시원히 말하지 그래? 뒤로 해 먹게 예산 좀 많이 책정해 달라고?","JPN":"もうはっきり言っちゃえば？　お小遣いが足りないから、もっと予算をくれって。","ENG":"Just be honest. You want a bigger budget so that you can fill your own pockets.","TWN":"你乾脆直說吧！想要多拿一些預算是吧？"},"stage":{"bg":"CLUB1","slots":{"L":null,"C":null,"R":null}}},{"id":"L18_1","type":"dialog","speaker":"HEAVYARMSCEO_NPC_ALPHA_NULL","text":{"KOREA":"쳇, 그러는 누님도 푼돈이나 만지는 주제에 뭐가 잘났는데?","JPN":"ちっ、そういう姉さんだって、はした金しか稼げないくせして偉そうだな。","ENG":"Hmpf, are you that good? You only make tiny money, don't you? ","TWN":"嗟！我說大姊，你以為你們是賺多少，在那邊囂張什麼？"},"stage":{"bg":"CLUB1","slots":{"L":null,"C":null,"R":null}}},{"id":"L19_1","type":"dialog","speaker":"ENTERTAINMENTCEO_NPC_ALPHA_NULL","text":{"KOREA":"뭐? 너 지금 뭐라고 했어?","JPN":"何ですって？　あんた今なんて言った？","ENG":"What did you just say?","TWN":"你說什麼？"},"stage":{"bg":"CLUB1","slots":{"L":null,"C":null,"R":null}}},{"id":"L20_1","type":"dialog","speaker":"HEAVYARMSCEO_NPC_ALPHA_NULL","text":{"KOREA":"할배 죽고 나서 알파트릭스 주가 떨어지는 게 원 데이 투 데이도 아니고….","JPN":"ジジイが死んで、アルファトリックスの株価が下落したのも昨日今日のことじゃねぇ……","ENG":"Alphatrix stock is dropping like a stone since grandpa died...","TWN":"爺爺死掉後，阿爾法崔克斯的股價就一直在跌…"},"stage":{"bg":"CLUB1","slots":{"L":null,"C":null,"R":null}}},{"id":"L21_1","type":"dialog","speaker":"HEAVYARMSCEO_NPC_ALPHA_NULL","text":{"KOREA":"우리 세대에서 올해 적자 면한 녀석이 있기는 해?","JPN":"俺らの世代で今年、赤字じゃないやつなんているのかよ。","ENG":"Is there any company which is actually in the black nowadays?","TWN":"我們當中有反虧為盈的傢伙嗎？"},"stage":{"bg":"CLUB1","slots":{"L":null,"C":null,"R":null}}},{"id":"L23_1","type":"dialog","speaker":"JIA_ALPHA_NULL_NULL","text":{"KOREA":"저기……. 오라버니.","JPN":"あの……お兄様。","ENG":"Um... Jaehyuk.","TWN":"那個……大哥。"},"stage":{"bg":"CLUB1","slots":{"L":null,"C":{"char_id":"JIA_ALPHA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"HEAVYARMSCEO_NPC_ALPHA_NULL","text":{"KOREA":"뭐야, 괴물. 넌 옆에서 실실 쪼개고나 있어.","JPN":"なんだ、化け物。お前は黙ってへらへらしとけ。","ENG":"What, you monster? You just keep smiling and saying nothing.","TWN":"幹嘛，怪物！你就給我在旁邊負責笑就好！"},"stage":{"bg":"CLUB1","slots":{"L":null,"C":{"char_id":"JIA_ALPHA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"JIA_ALPHA_NULL_NULL","text":{"KOREA":"아뇨. 뭔가 착오가 있는 것 같아서요.","JPN":"いえ、何か勘違いされているようなので。","ENG":"No, I believe you’re mistaken.","TWN":"不是的，好像有什麼誤會？"},"stage":{"bg":"CLUB1","slots":{"L":null,"C":{"char_id":"JIA_ALPHA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"JIA_ALPHA_NULL_NULL","text":{"KOREA":"저희 알파트릭스 이노베이션은 올해 상반기도 흑자래요. 하반기 전망도 밝은 편이고요.","JPN":"私のアルファトリックス・イノベーションは今年の上半期も黒字だそうです。下半期の展望も明るいですし。","ENG":"Alphatrix Innovation is in the black. Also we’re expecting a positive earnings report for the second half of the year.","TWN":"我們阿爾法崔克斯改革今年上半年是有盈餘的，下半年也很樂觀喔。"},"stage":{"bg":"CLUB1","slots":{"L":null,"C":{"char_id":"JIA_ALPHA_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"HEAVYARMSCEO_NPC_ALPHA_NULL","text":{"KOREA":"…그래서, 너 잘났다 이거냐?","JPN":"……だからなんだ、自分は凄いってか？","ENG":"Are you trying to bust my chops here?","TWN":"…所以你想說的是你好棒棒嗎？"},"stage":{"bg":"CLUB1","slots":{"L":null,"C":{"char_id":"JIA_ALPHA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"JIA_ALPHA_NULL_NULL","text":{"KOREA":"아. 그런 의미로 말씀드린 건 아니에요.","JPN":"あ、そういった意味でお話したわけではありません。","ENG":"No, I didn’t mean that.","TWN":"喔，我不是這個意思。"},"stage":{"bg":"CLUB1","slots":{"L":null,"C":{"char_id":"JIA_ALPHA_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}}]`);export{e as default};